#include <iostream>
#include <queue>

class MyStack {
public:
    void push(int x) {
        front_queue.push(x);
    }

    int pop() {
        if (is_empty()) return -1;
        return rear_queue.front();
    }

    int top() {
        return front_queue.front();
    }

    bool empty() {
        return front_queue.empty() && rear_queue.empty();
    }

private:
    std::queue<int> front_queue;
    std::queue<int> rear_queue;
};
